#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Council diagnostic: measure TRUE sync enrichment rate (re-enrich paused -> done-count
is monotonic, so its delta = real gross rate) + inspect the sync worker's claim SQL/txn +
enrich_queue indexes. Tells us whether to just scale sync, or fix claiming first."""
import os,sys,json,time,subprocess
def sh(c,t=20):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
def psql(q,t=18):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc","SET statement_timeout='12s'; "+q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip().split('\n')[-1] if r.returncode==0 and r.stdout.strip() else None)
out={"kind":"council_diag","ts":int(time.time())}
try:
    d0=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue")
    t0=time.time(); time.sleep(45)
    d1=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue"); t1=time.time()
    out["done_t0"]=d0; out["done_t1"]=d1
    try: out["TRUE_sync_per_min"]=round((int(d1)-int(d0))*60.0/(t1-t0),1)
    except Exception: pass
    out["active_conns"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'")
    out["pg_conns"]=psql("SELECT count(*)||'/'||current_setting('max_connections') FROM pg_stat_activity")
    # which file does enrich-pool run?
    out["pool_exec"]=sh("systemctl cat atlas-enrich-pool@1.service 2>/dev/null | grep -iE 'ExecStart|Environment' | head")
    # claim SQL + SKIP LOCKED + txn in the worker source(s)
    for f in ["/opt/atlas/importers/atlas_enrich_pool.py","/opt/atlas/importers/atlas_enrich_worker.py","/opt/atlas/enrich/atlas_enrich_pool.py"]:
        if os.path.exists(f):
            out["worker_file"]=f
            out["claim_sql"]=sh("grep -nE 'SELECT|UPDATE|SKIP LOCKED|FOR UPDATE|commit|autocommit|BEGIN|enrich_queue|status=' %s | head -30"%f)
            break
    # enrich_queue indexes
    out["queue_indexes"]=sh("sudo -u postgres psql tuanichat_atlas -tAc \"SELECT indexname||':'||indexdef FROM pg_indexes WHERE schemaname='atlas' AND tablename='enrich_queue'\" 2>/dev/null | head")
    out["queue_status_dist"]=psql("SELECT status||':'||count(*) FROM atlas.enrich_queue GROUP BY status ORDER BY 2 DESC")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/council-diag.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"council_diag","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
